import React from 'react';

const CoursesPage = () => {
  return (
    <div className="container mx-auto py-8 px-4">
      <h1 className="text-3xl font-bold text-blue-900 mb-6">课程列表</h1>
      <p className="text-gray-600 mb-8">课程页面正在开发中，敬请期待...</p>
      
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {[1, 2, 3, 4, 5, 6].map((item) => (
          <div key={item} className="bg-white rounded-lg shadow-md overflow-hidden">
            <div className="h-48 bg-gray-200"></div>
            <div className="p-4">
              <h2 className="text-xl font-semibold mb-2">示例课程 {item}</h2>
              <p className="text-gray-600 mb-4">这是一个示例课程，实际内容正在开发中...</p>
              <button className="bg-blue-900 text-white px-4 py-2 rounded-md hover:bg-blue-800">
                查看详情
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CoursesPage;
